import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it.todo("should return premium of 5 G (processing fee only) for an empty item list");
  it.todo("should compute premium for a single plain sword (100 G base + 10 G first insurance + 5 G fee = 115 G)");
  it.todo("should compute premium for a single plain amulet (60 + 6 + 5 = 71 G)");
  it.todo("should compute premium for a single plain staff (80 + 8 + 5 = 93 G)");
  it.todo("should compute premium for a single plain potion (40 + 4 + 5 = 49 G)");

  // Quote: components and blocks
  it.todo("should compute premium for 2 runes (50 G base + 5 G first insurance + 5 G fee = 60 G)");
  it.todo("should apply block discount for 3 alike runes (60 G base + 6 G first insurance + 5 G fee = 71 G)");
  it.todo("should not apply block for 4 runes (100 G base)");
  it.todo("should treat 2 runes + 1 moonstone as different types (no block)");
  it.todo("should apply two separate blocks for 3 runes + 3 moonstones");

  // Quote: premium modifiers
  it.todo("should add 50% curse surcharge on cursed items (item-specific)");
  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");
  it.todo("should apply 20% loyalty discount for customers with >= 2 years");
  it.todo("should apply 15% follow-up discount on contracts after the first");
  it.todo("should round premium up (in MHPCO favor)");

  // Quote: multi-item policy
  it.todo("should combine cursed sword + plain amulet correctly (newcomer cursed sword example yields 165 G)");
  it.todo("should handle long-standing customer second contract integration example (160 G)");

  // Claim: basic
  it.todo("should pay damage minus 100 G deductible for a regular sword");
  it.todo("should pay 50% for high-enchantment item (>=8) then deduct 100 G");
  it.todo("should fully reimburse dragon-material items then deduct 100 G");
  it.todo("should apply deductible per damaged item separately");
  it.todo("should cap total payout at twice the insurance sum");

  // CLI errors
  it.todo("should reject quote with unknown item type (throws error)");
  it.todo("should reject claim referencing item not in policy (throws error)");
  it.todo("should reject claim with negative damage amount (throws error)");
  it.todo("should reject claim with more damage entries of a type than policy covers (throws error)");
});

