const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

interface Item {
  type: string;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const quotePremium = (items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const base = items.reduce((sum, it) => sum + BASE_PREMIUM[it.type], 0);
  return Math.ceil(base * (1 + FIRST_INSURANCE_RATE)) + PROCESSING_FEE;
};

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items ?? []),
  }));
  return { results };
};

