const PROCESSING_FEE = 5;
const FIRST_INSURANCE_PERCENT = 10;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
};

interface Item {
  type: string;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const applyFirstInsuranceSurcharge = (base: number): number =>
  Math.ceil((base * (100 + FIRST_INSURANCE_PERCENT)) / 100);

const quotePremium = (items: Item[]): number =>
  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items ?? []),
  }));
  return { results };
};

