const PROCESSING_FEE = 5;
const FIRST_INSURANCE_PERCENT = 10;
const PERCENT_BASE = 100;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
  material?: string;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const CURSE_SURCHARGE_PERCENT = 50;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const percentOf = (amount: number, percent: number): number =>
  (amount * percent) / PERCENT_BASE;

const itemBasePremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  const curse = item.cursed ? percentOf(base, CURSE_SURCHARGE_PERCENT) : 0;
  return base + curse;
};

const sumBase = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0);

const partitionByType = (items: Item[]): Item[][] => {
  const groups: Record<string, Item[]> = {};
  items.forEach((item) => (groups[item.type] ??= []).push(item));
  return Object.values(groups);
};

const priceGroup = (group: Item[]): number =>
  group.length === BLOCK_SIZE && isComponent(group[0])
    ? BLOCK_PREMIUM
    : sumBase(group);

const sumBasePremiums = (items: Item[]): number =>
  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);

const applyFirstInsuranceSurcharge = (base: number): number =>
  Math.ceil(base + percentOf(base, FIRST_INSURANCE_PERCENT));

const quotePremium = (items: Item[]): number =>
  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;

const executeStep = (step: Step): { premium: number } => ({
  premium: quotePremium(step.items ?? []),
});

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map(executeStep) };
};

