const PROCESSING_FEE = 5;
const FIRST_INSURANCE_PERCENT = 10;
const PERCENT_BASE = 100;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
  material?: string;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const CURSE_SURCHARGE_PERCENT = 50;
const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_PERCENT = 20;
const LOYALTY_THRESHOLD_YEARS = 2;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface Customer {
  yearsWithMHPCO: number;
}

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const percentOf = (amount: number, percent: number): number =>
  (amount * percent) / PERCENT_BASE;

const percentIf = (condition: boolean, base: number, percent: number): number =>
  condition ? percentOf(base, percent) : 0;

const itemBasePremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  const curse = percentIf(item.cursed === true, base, CURSE_SURCHARGE_PERCENT);
  const highEnchantment = percentIf(
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
    base,
    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
  );
  return base + curse + highEnchantment;
};

const sumBase = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0);

const partitionByType = (items: Item[]): Item[][] => {
  const groups: Record<string, Item[]> = {};
  items.forEach((item) => (groups[item.type] ??= []).push(item));
  return Object.values(groups);
};

const priceGroup = (group: Item[]): number =>
  group.length === BLOCK_SIZE && isComponent(group[0])
    ? BLOCK_PREMIUM
    : sumBase(group);

const sumBasePremiums = (items: Item[]): number =>
  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);

const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;

const applyPolicyModifiers = (base: number, customer: Customer): number => {
  const firstInsurance = percentOf(base, FIRST_INSURANCE_PERCENT);
  const loyalty = percentIf(isLoyalCustomer(customer), base, LOYALTY_DISCOUNT_PERCENT);
  return base + firstInsurance - loyalty;
};

const quotePremium = (items: Item[], customer: Customer): number =>
  Math.ceil(applyPolicyModifiers(sumBasePremiums(items), customer)) + PROCESSING_FEE;

const executeStep = (step: Step, customer: Customer): { premium: number } => ({
  premium: quotePremium(step.items ?? [], customer),
});

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  return {
    results: scenario.steps.map((step) => executeStep(step, scenario.customer)),
  };
};

import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it("should return premium of 5 G (processing fee only) for an empty item list", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("should compute premium for a single plain sword (100 G base + 10 G first insurance + 5 G fee = 115 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("should compute premium for a single plain amulet (60 + 6 + 5 = 71 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("should compute premium for a single plain staff (80 + 8 + 5 = 93 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("should compute premium for a single plain potion (40 + 4 + 5 = 49 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // Quote: components and blocks
  it("should compute premium for 2 runes (50 G base + 5 G first insurance + 5 G fee = 60 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("should apply block discount for 3 alike runes (60 G base + 6 G first insurance + 5 G fee = 71 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("should not apply block for 4 runes (100 G base + 10 G first insurance + 5 G fee = 115 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("should treat 2 runes + 1 moonstone as different types (no block, base 75 G, premium 88 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("should apply two separate blocks for 3 runes + 3 moonstones (120 G base, premium 137 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // Quote: premium modifiers
  it("should add 50% curse surcharge on cursed sword (100 + 50 curse, then 15 first insurance + 5 fee = 170 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 170 });
  });
  it("should add 30% high-enchantment surcharge for enchantment >= 5 (sword e=5: 100+30 then +13 first ins +5 fee = 148)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 148 });
  });
  it("should apply 20% loyalty discount for >=2-year customers (sword 100, -20 loyalty +10 first ins +5 fee = 95)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 95 });
  });
  it.todo("should apply 15% follow-up discount on contracts after the first");
  it.todo("should round premium up (in MHPCO favor)");

  // Quote: multi-item policy
  it.todo("should combine cursed sword + plain amulet correctly (newcomer cursed sword example yields 165 G)");
  it.todo("should handle long-standing customer second contract integration example (160 G)");

  // Claim: basic
  it.todo("should pay damage minus 100 G deductible for a regular sword");
  it.todo("should pay 50% for high-enchantment item (>=8) then deduct 100 G");
  it.todo("should fully reimburse dragon-material items then deduct 100 G");
  it.todo("should apply deductible per damaged item separately");
  it.todo("should cap total payout at twice the insurance sum");

