const policyInsuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);

const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const processClaim = (
  step: Step,
  policyItems: Item[],
): { payout: number; remainingCap: number } => {
  const damages = step.incident?.damages ?? [];
  const payout = damages.reduce((sum, d) => sum + damagePayout(d), 0);
  const cap = policyInsuranceSum(policyItems) * CAP_MULTIPLIER;
  return { payout, remainingCap: cap - payout };
};

const isQuote = (step: Step): boolean => step.op === "quote";

const precedingQuoteCount = (steps: Step[], index: number): number =>
  steps.slice(0, index).filter(isQuote).length;

